final:
module rrt_node_selector (  
    input clk,  
    input rst,  
    input [2:0] node_id,  
    output reg [2:0] selected_node  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            selected_node <= 3'b000;  
        else  
            selected_node <= (node_id == 3'b111) ? 3'b000 : node_id + 1;  
    end  
endmodule
